\usepackage{xcolor}

\definecolor{K5_Indigo}{HTML}{2b0c81}
\definecolor{K5_Blue}{HTML}{539df7}

\begin{document}
    \begin{tikzpicture}[
        node distance=3cm,
        box/.style={draw=K5_Indigo, line width=2pt, minimum width=2.5cm, minimum height=1.5cm, font=\Huge\bfseries, text=K5_Indigo, rounded corners=5pt},
        arrow/.style={-Stealth, draw=K5_Blue, line width=3pt}
    ]
        \node[box] (mm) {mm};
        \node[box, right=of mm] (cm) {cm};
        \draw[arrow] (mm) -- (cm) node[midway, above=0.2cm, text=K5_Indigo, font=\Large\bfseries] {Divide by 10};
    \end{tikzpicture}
